const rows = items.map(item => item.json);

function isMissing(value) {
  return value === null || value === undefined || value === "";
}

function isNumeric(value) {
  return !isMissing(value) && !isNaN(Number(value));
}

function mean(values) {
  return values.reduce((a, b) => a + b, 0) / values.length;
}

function median(values) {
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2;
}

const columns = [...new Set(rows.flatMap(row => Object.keys(row)))];

const missingValues = {};
const numericSummary = {};
const categoricalSummary = {};

for (const column of columns) {
  const values = rows.map(row => row[column]);
  const nonMissing = values.filter(value => !isMissing(value));
  const numericValues = nonMissing.filter(isNumeric).map(Number);

  missingValues[column] = values.length - nonMissing.length;

  if (numericValues.length > 0 && numericValues.length >= nonMissing.length * 0.8) {
    numericSummary[column] = {
      count: numericValues.length,
      mean: Number(mean(numericValues).toFixed(2)),
      median: Number(median(numericValues).toFixed(2)),
      min: Math.min(...numericValues),
      max: Math.max(...numericValues)
    };
  } else {
    const counts = {};
    for (const value of nonMissing) {
      counts[String(value)] = (counts[String(value)] || 0) + 1;
    }

    categoricalSummary[column] = Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 10)
      .map(([category, count]) => ({
        category,
        count,
        percentage: Number(((count / rows.length) * 100).toFixed(2))
      }));
  }
}

return [{
  json: {
    report_title: "Automated Data Analysis Summary",
    row_count: rows.length,
    column_count: columns.length,
    columns,
    missing_values: missingValues,
    numeric_summary: numericSummary,
    categorical_summary: categoricalSummary
  }
}];

const rawRows = items.map(item => item.json);

function isMissing(value) {
  if (value === null || value === undefined) return true;
  if (typeof value === "string") {
    const v = value.trim().toLowerCase();
    return ["", "na", "n/a", "null", "none", "nan", "-", "--"].includes(v);
  }
  return false;
}

function cleanColumnName(name) {
  return String(name)
    .trim()
    .toLowerCase()
    .replace(/[^a-zA-Z0-9]+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_|_$/g, "");
}

function cleanText(value) {
  if (isMissing(value)) return null;

  if (typeof value !== "string") return value;

  let cleaned = value.trim();

  // Remove unnecessary symbols at beginning/end only
  cleaned = cleaned.replace(/^[+\-*_\s]+/, "");
  cleaned = cleaned.replace(/[+\-*_\s]+$/, "");

  // Normalize multiple spaces
  cleaned = cleaned.replace(/\s+/g, " ");

  return cleaned === "" ? null : cleaned;
}

function looksNumeric(value) {
  if (isMissing(value)) return false;
  if (typeof value === "number") return true;

  const cleaned = String(value)
    .trim()
    .replace(/,/g, "")
    .replace(/\$/g, "")
    .replace(/%/g, "");

  return cleaned !== "" && !isNaN(Number(cleaned));
}

function toNumber(value) {
  if (isMissing(value)) return null;

  if (typeof value === "number") return value;

  const cleaned = String(value)
    .trim()
    .replace(/,/g, "")
    .replace(/\$/g, "")
    .replace(/%/g, "");

  return cleaned === "" || isNaN(Number(cleaned)) ? null : Number(cleaned);
}

function median(values) {
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2;
}

function mode(values) {
  const counts = {};
  for (const value of values) {
    const key = String(value);
    counts[key] = (counts[key] || 0) + 1;
  }

  return Object.entries(counts).sort((a, b) => b[1] - a[1])[0]?.[0] ?? null;
}

// 1. Clean column names and text values
let rows = rawRows.map(row => {
  const cleanedRow = {};

  for (const [key, value] of Object.entries(row)) {
    const cleanKey = cleanColumnName(key);
    cleanedRow[cleanKey] = cleanText(value);
  }

  return cleanedRow;
});

// 2. Remove completely empty rows
rows = rows.filter(row =>
  Object.values(row).some(value => !isMissing(value))
);

// 3. Detect numeric columns
const columns = [...new Set(rows.flatMap(row => Object.keys(row)))];
const numericColumns = [];

for (const column of columns) {
  const values = rows.map(row => row[column]).filter(value => !isMissing(value));
  const numericCount = values.filter(looksNumeric).length;

  if (values.length > 0 && numericCount / values.length >= 0.8) {
    numericColumns.push(column);
  }
}

// 4. Convert numeric columns to numbers
for (const row of rows) {
  for (const column of numericColumns) {
    row[column] = toNumber(row[column]);
  }
}

// 5. Impute missing values
const imputationLog = {};

for (const column of columns) {
  const values = rows.map(row => row[column]).filter(value => !isMissing(value));

  if (values.length === 0) continue;

  let replacement;

  if (numericColumns.includes(column)) {
    replacement = median(values.map(Number));
  } else {
    replacement = mode(values);
  }

  let count = 0;

  for (const row of rows) {
    if (isMissing(row[column])) {
      row[column] = replacement;
      count++;
    }
  }

  if (count > 0) {
    imputationLog[column] = {
      missing_values_filled: count,
      method: numericColumns.includes(column) ? "median" : "mode",
      replacement_value: replacement
    };
  }
}

// 6. Remove exact duplicate rows
const seen = new Set();
const deduplicatedRows = [];

for (const row of rows) {
  const signature = JSON.stringify(row);

  if (!seen.has(signature)) {
    seen.add(signature);
    deduplicatedRows.push(row);
  }
}

const cleaningSummary = {
  original_row_count: rawRows.length,
  cleaned_row_count: deduplicatedRows.length,
  duplicate_rows_removed: rows.length - deduplicatedRows.length,
  numeric_columns_detected: numericColumns,
  imputation_log: imputationLog
};

// 7. Return cleaned rows
return deduplicatedRows.map(row => ({
  json: row
}));

