function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function formatName(name) {
  return String(name)
    .replaceAll("_", " ")
    .replace(/\b\w/g, c => c.toUpperCase());
}

function formatNumber(value) {
  if (typeof value !== "number") return escapeHtml(value);
  return Number.isInteger(value) ? value.toLocaleString() : value.toFixed(2);
}

function markdownToHtml(text) {
  let safe = escapeHtml(text);

  safe = safe.replace(/^### (.*$)/gim, "<h3>$1</h3>");
  safe = safe.replace(/^## (.*$)/gim, "<h2>$1</h2>");

  safe = safe.replace(/\*\*(.*?)\*\*/g, (match, content) => {
    if (content.includes("_")) {
      return `<strong>${content}</strong>`;
    }
    return `<h4>${content}</h4>`;
  });

  safe = safe.replace(/^\*   (.*$)/gim, "<li>$1</li>");
  safe = safe.replace(/^\* (.*$)/gim, "<li>$1</li>");
  safe = safe.replace(/\n\n/g, "<br><br>");

  return safe;
}

function makeCategoricalCharts(categoricalSummary) {
  let chartHtml = "";
  let chartScripts = "";
  let chartIndex = 0;

  for (const [column, values] of Object.entries(categoricalSummary || {})) {
    if (!Array.isArray(values) || values.length === 0) continue;

    const labels = values.map(v => String(v.category));
    const counts = values.map(v => Number(v.count));
    const safeColumnName = formatName(column);

    chartHtml += `
      <section>
        <h2>${safeColumnName} Distribution</h2>
        <div class="dual-chart-grid">
          <div class="chart-card">
            <h3>Sample Distribution</h3>
            <div class="chart-wrap small-chart">
              <canvas id="catBarChart${chartIndex}"></canvas>
            </div>
          </div>

          <div class="chart-card">
            <h3>Category Share</h3>
            <div class="chart-wrap small-chart">
              <canvas id="catPieChart${chartIndex}"></canvas>
            </div>
          </div>
        </div>
      </section>
    `;

    chartScripts += `
      new Chart(document.getElementById("catBarChart${chartIndex}"), {
        type: "bar",
        data: {
          labels: ${JSON.stringify(labels)},
          datasets: [{
            label: "Count",
            data: ${JSON.stringify(counts)},
            borderRadius: 8
          }]
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: false },
            title: {
              display: true,
              text: "${safeColumnName} Count Distribution"
            }
          },
          scales: {
            y: { beginAtZero: true }
          }
        }
      });

      new Chart(document.getElementById("catPieChart${chartIndex}"), {
        type: "pie",
        data: {
          labels: ${JSON.stringify(labels)},
          datasets: [{
            label: "Share",
            data: ${JSON.stringify(counts)}
          }]
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            title: {
              display: true,
              text: "${safeColumnName} Percentage Share"
            }
          }
        }
      });
    `;

    chartIndex++;
  }

  return {
    chartHtml,
    chartScripts
  };
}

const numericSummary = data.numeric_summary || {};
const missingValues = data.missing_values || {};
const categoricalSummary = data.categorical_summary || {};
const numericColumns = Object.keys(numericSummary);
const totalMissing = Object.values(missingValues).reduce((a, b) => a + b, 0);
const categoricalCharts = makeCategoricalCharts(categoricalSummary);

const kpiCards = Object.entries(numericSummary).map(([name, stats]) => `
  <div class="kpi-card">
    <div class="kpi-label">${formatName(name)}</div>
    <div class="kpi-value">${formatNumber(stats.mean)}</div>
    <div class="kpi-sub">Median ${formatNumber(stats.median)} · Range ${formatNumber(stats.min)}–${formatNumber(stats.max)}</div>
  </div>
`).join("");

const numericRows = Object.entries(numericSummary).map(([name, stats]) => {
  const range = stats.max - stats.min || 1;
  const meanPosition = ((stats.mean - stats.min) / range) * 100;

  return `
    <tr>
      <td>${formatName(name)}</td>
      <td>${formatNumber(stats.count)}</td>
      <td>${formatNumber(stats.mean)}</td>
      <td>${formatNumber(stats.median)}</td>
      <td>${formatNumber(stats.min)}</td>
      <td>${formatNumber(stats.max)}</td>
      <td>
        <div class="range-bar">
          <div class="range-dot" style="left:${meanPosition}%"></div>
        </div>
      </td>
    </tr>
  `;
}).join("");

const missingRows = Object.entries(missingValues).map(([name, count]) => `
  <tr>
    <td>${formatName(name)}</td>
    <td>${formatNumber(count)}</td>
    <td>${count === 0 ? "Clean" : "Needs review"}</td>
  </tr>
`).join("");

const categoricalRows = Object.entries(categoricalSummary).map(([column, values]) => {
  return values.map(item => `
